#pragma once

#include "esphome/core/component.h"
#include "esphome/core/gpio.h"
#include "esphome/components/sensor/sensor.h"
#include "esphome/components/number/number.h"
#include "esphome/components/text_sensor/text_sensor.h"
#include "button_injector.h"

#include <string>

namespace esphome {
namespace tublemetry_display {

// Component version — update on each meaningful firmware change
static const char *const TUBLEMETRY_VERSION = "0.2.0";

// 7-segment lookup table entry
struct SegEntry {
  uint8_t segments;  // 7-bit value (dp masked off)
  char character;    // decoded character
};

// Frame constants
static const uint8_t BITS_PER_FRAME = 24;
static const uint8_t DIGITS_PER_FRAME = 3;
static const uint8_t BITS_PER_DIGIT = 7;

// ISR-shared frame data (volatile, accessed from interrupt context)
struct FrameData {
  volatile uint32_t bits;          // accumulated bits (MSB-first)
  volatile uint8_t bit_count;      // bits collected in current frame
  volatile uint32_t last_frame;    // last completed frame (24 bits)
  volatile bool frame_ready;       // new frame available for processing
  volatile uint32_t last_edge_us;  // micros() of last clock rising edge
  volatile uint32_t frame_count;   // total frames decoded (diagnostic)
};

/// Main component: reads synchronous clock+data GPIO and decodes display frames.
class TublemetryDisplay : public Component {
 public:
  void setup() override;
  void loop() override;
  float get_setup_priority() const override;

  // GPIO pin setters (called from Python codegen)
  void set_clock_pin(InternalGPIOPin *pin) { this->clock_pin_ = pin; }
  void set_data_pin(InternalGPIOPin *pin) { this->data_pin_ = pin; }

  // Button injector setter
  void set_button_injector(ButtonInjector *injector) { this->injector_ = injector; }

  // Diagnostic sensor setters
  void set_display_string_sensor(text_sensor::TextSensor *s) { this->display_string_sensor_ = s; }
  void set_raw_hex_sensor(text_sensor::TextSensor *s) { this->raw_hex_sensor_ = s; }
  void set_display_state_sensor(text_sensor::TextSensor *s) { this->display_state_sensor_ = s; }
  void set_decode_confidence_sensor(sensor::Sensor *s) { this->decode_confidence_sensor_ = s; }
  void set_temperature_sensor(sensor::Sensor *s) { this->temperature_sensor_ = s; }
  void set_setpoint_number(number::Number *n) { this->setpoint_number_ = n; }
  void set_digit_values_sensor(text_sensor::TextSensor *s) { this->digit_values_sensor_ = s; }
  void set_last_update_sensor(text_sensor::TextSensor *s) { this->last_update_sensor_ = s; }
  void set_version_sensor(text_sensor::TextSensor *s) { this->version_sensor_ = s; }

  // Test helpers — single raw button press for hardware validation
  void test_press_up() { if (this->injector_ != nullptr) this->injector_->press_once(true); }
  void test_press_down() { if (this->injector_ != nullptr) this->injector_->press_once(false); }

  // ISR handler (must be public for static trampoline)
  void IRAM_ATTR clock_isr_();

 protected:
  // GPIO pins
  InternalGPIOPin *clock_pin_{nullptr};
  InternalGPIOPin *data_pin_{nullptr};

  // Button injector (optional — nullptr if no output pins configured)
  ButtonInjector *injector_{nullptr};

  // ISR-shared data
  FrameData isr_data_{};

  // Data pin GPIO number (cached for fast ISR access)
  uint8_t data_gpio_num_{0};

  // State tracking (publish only on change)
  float last_confidence_{-1.0f};
  std::string last_display_string_;
  std::string last_display_state_;
  std::string last_raw_hex_;
  std::string last_digit_values_;

  // Stability filter — accumulate consecutive identical decoded frames before publishing
  std::string candidate_display_string_;
  uint8_t stable_count_{0};
  static constexpr uint8_t STABLE_THRESHOLD = 3;

  // Diagnostic sensor pointers
  text_sensor::TextSensor *display_string_sensor_{nullptr};
  text_sensor::TextSensor *raw_hex_sensor_{nullptr};
  text_sensor::TextSensor *display_state_sensor_{nullptr};
  sensor::Sensor *decode_confidence_sensor_{nullptr};
  sensor::Sensor *temperature_sensor_{nullptr};
  number::Number *setpoint_number_{nullptr};
  text_sensor::TextSensor *digit_values_sensor_{nullptr};
  text_sensor::TextSensor *last_update_sensor_{nullptr};
  text_sensor::TextSensor *version_sensor_{nullptr};

  // Internal methods
  void process_frame_(uint32_t frame_bits);
  char decode_7seg_(uint8_t byte_val);
  void classify_display_state_(const std::string &display_str);
  void publish_timestamp_();
};

}  // namespace tublemetry_display
}  // namespace esphome

#include "tublemetry_display.h"
#include "esphome/core/log.h"
#include "esphome/core/hal.h"

#include <cstdio>
#include <cstring>

namespace esphome {
namespace tublemetry_display {

static const char *const TAG = "tublemetry_display";

// 7-segment lookup table.
// Ported from Python src/tublemetry/decode.py SEVEN_SEG_TABLE.
// Segment mapping: bit6=a, bit5=b, bit4=c, bit3=d, bit2=e, bit1=f, bit0=g
// Values are masked to 7 bits (dp bit 7 stripped before lookup).
//
// Format: {hex_value, 'character'}, // status
// Cross-check test (tests/test_cross_check.py) parses this table to verify
// it matches the Python reference.
//
// SEVEN_SEG_TABLE_START
static const SegEntry SEVEN_SEG_TABLE[] = {
    {0x7E, '0'},  // confirmed (ladder capture 2026-03-20)
    {0x30, '1'},  // confirmed (ladder capture 2026-03-20)
    {0x34, '1'},  // confirmed (setpoint display mode — "1" with lower-left foot segment e)
    {0x6D, '2'},  // confirmed (ladder capture 2026-03-20)
    {0x79, '3'},  // confirmed (ladder capture 2026-03-20)
    {0x33, '4'},  // confirmed (ladder capture 2026-03-20)
    {0x5B, '5'},  // confirmed (ladder capture 2026-03-20)
    {0x5F, '6'},  // confirmed (ladder capture 2026-03-20)
    {0x70, '7'},  // confirmed (ladder capture 2026-03-20)
    {0x7F, '8'},  // confirmed (ladder capture 2026-03-20)
    {0x73, '9'},  // confirmed (ladder capture 2026-03-20) -- NOT 0x7B, no bottom segment
    {0x00, ' '},  // confirmed (blank)
    {0x37, 'H'},  // confirmed (OH.csv decode)
    {0x0E, 'L'},  // confirmed (SL mode capture 2026-03-20)
    {0x4F, 'E'},  // confirmed (Ec mode capture 2026-03-20)
    {0x0D, 'c'},  // confirmed (Ec mode capture 2026-03-20)
    {0x0F, 't'},  // confirmed (St mode capture 2026-03-20)
    {0x67, 'P'},  // unverified (GS510SZ reference)
    {0x01, '-'},  // unverified (GS510SZ reference)
    {0x03, '-'},  // unverified (alternate dash encoding)
    {0x05, 'r'},  // unverified (GS510SZ reference)
    {0x1D, 'o'},  // unverified (GS510SZ reference)
};
// SEVEN_SEG_TABLE_END

static const size_t SEVEN_SEG_TABLE_SIZE = sizeof(SEVEN_SEG_TABLE) / sizeof(SEVEN_SEG_TABLE[0]);

// Frame gap threshold in microseconds.
// At 60Hz, frames are 16.7ms apart. Clock pulses within a frame are ~37us apart.
// A gap > 500us between clock edges means a new frame.
static const uint32_t FRAME_GAP_US = 500;

// Minimum microseconds between valid clock edges (noise rejection).
// Real clock pulses are ~37us apart; anything shorter is floating-pin noise.
static const uint32_t MIN_PULSE_US = 10;

// Static instance pointer for ISR trampoline
static TublemetryDisplay *isr_instance_ = nullptr;

/// ISR trampoline -- static function that calls instance method
static void IRAM_ATTR clock_isr_trampoline(TublemetryDisplay *instance) {
  if (instance != nullptr) {
    instance->clock_isr_();
  } else if (isr_instance_ != nullptr) {
    isr_instance_->clock_isr_();
  }
}

/// ISR: called on every clock rising edge. Samples data pin and accumulates bits.
void IRAM_ATTR TublemetryDisplay::clock_isr_() {
  uint32_t now = micros();

  // Reject noise: ignore edges closer than MIN_PULSE_US apart
  uint32_t elapsed = now - this->isr_data_.last_edge_us;
  if (elapsed < MIN_PULSE_US) {
    return;
  }

  // Detect frame boundary: gap > FRAME_GAP_US means new frame
  if (this->isr_data_.bit_count > 0 && (now - this->isr_data_.last_edge_us) > FRAME_GAP_US) {
    // Previous bits form a complete frame if we got 24
    if (this->isr_data_.bit_count == BITS_PER_FRAME) {
      this->isr_data_.last_frame = this->isr_data_.bits;
      this->isr_data_.frame_ready = true;
      this->isr_data_.frame_count++;
    }
    // Reset for new frame
    this->isr_data_.bits = 0;
    this->isr_data_.bit_count = 0;
  }

  this->isr_data_.last_edge_us = now;

  // Sample data pin and shift into frame buffer (MSB-first)
  uint8_t data_bit = gpio_get_level(static_cast<gpio_num_t>(this->data_gpio_num_));
  this->isr_data_.bits = (this->isr_data_.bits << 1) | data_bit;
  this->isr_data_.bit_count++;

  // If we've collected a full frame, make it available immediately
  if (this->isr_data_.bit_count == BITS_PER_FRAME) {
    this->isr_data_.last_frame = this->isr_data_.bits;
    this->isr_data_.frame_ready = true;
    this->isr_data_.frame_count++;
    // Don't reset yet -- let the gap detection handle the boundary
  }
}

/// Decode a 7-segment byte value to its character.
/// Masks off bit 7 (decimal point) before lookup.
/// Returns '?' for unknown byte patterns.
char TublemetryDisplay::decode_7seg_(uint8_t byte_val) {
  uint8_t segments = byte_val & 0x7F;  // mask off dp (bit 7)

  for (size_t i = 0; i < SEVEN_SEG_TABLE_SIZE; i++) {
    if (SEVEN_SEG_TABLE[i].segments == segments) {
      return SEVEN_SEG_TABLE[i].character;
    }
  }

  ESP_LOGV(TAG, "Unknown 7-segment byte: 0x%02X (masked: 0x%02X)", byte_val, segments);
  return '?';
}

// --- TublemetryDisplay (main component) ---

void TublemetryDisplay::setup() {
  ESP_LOGI(TAG, "Tublemetry display decoder starting (GPIO interrupt mode)");

  if (this->clock_pin_ == nullptr || this->data_pin_ == nullptr) {
    ESP_LOGE(TAG, "Clock or data pin not configured");
    this->mark_failed();
    return;
  }

  // Configure pins
  this->clock_pin_->setup();
  this->data_pin_->setup();

  // Cache data pin GPIO number for fast ISR access
  this->data_gpio_num_ = this->data_pin_->get_pin();

  ESP_LOGI(TAG, "Clock pin: GPIO%d, Data pin: GPIO%d",
           this->clock_pin_->get_pin(), this->data_gpio_num_);
  ESP_LOGI(TAG, "7-segment table entries: %d", (int) SEVEN_SEG_TABLE_SIZE);

  // Initialize ISR data
  memset((void *) &this->isr_data_, 0, sizeof(this->isr_data_));

  // Set up ISR trampoline
  isr_instance_ = this;
  this->clock_pin_->attach_interrupt(clock_isr_trampoline, this, gpio::INTERRUPT_RISING_EDGE);

  ESP_LOGI(TAG, "Clock interrupt attached, waiting for frames...");

  // Publish component version
  ESP_LOGI(TAG, "Tublemetry version: %s", TUBLEMETRY_VERSION);
  if (this->version_sensor_ != nullptr) {
    this->version_sensor_->publish_state(TUBLEMETRY_VERSION);
  }

  // Set up button injector if configured
  if (this->injector_ != nullptr) {
    this->injector_->setup();
  }
}

void TublemetryDisplay::loop() {
  // Drive button injector state machine (non-blocking)
  if (this->injector_ != nullptr) {
    this->injector_->loop();
  }

  // Copy frame from ISR with interrupts disabled to prevent torn reads
  portDISABLE_INTERRUPTS();
  bool has_frame = this->isr_data_.frame_ready;
  uint32_t frame_bits = this->isr_data_.last_frame;
  if (has_frame) this->isr_data_.frame_ready = false;
  portENABLE_INTERRUPTS();

  if (!has_frame) {
    return;
  }

  this->process_frame_(frame_bits);
}

float TublemetryDisplay::get_setup_priority() const {
  return setup_priority::DATA;
}

/// Process a complete 24-bit frame: extract 3 digits and 3 status bits.
void TublemetryDisplay::process_frame_(uint32_t frame_bits) {
  // Extract 3 x 7-bit digits (MSB-first from bit 23 down)
  // Frame layout: [digit1:7][digit2:7][digit3:7][status:3]
  uint8_t digit_bytes[DIGITS_PER_FRAME];
  digit_bytes[0] = (frame_bits >> 17) & 0x7F;  // bits 23-17
  digit_bytes[1] = (frame_bits >> 10) & 0x7F;  // bits 16-10
  digit_bytes[2] = (frame_bits >> 3) & 0x7F;   // bits 9-3
  uint8_t status = frame_bits & 0x07;           // bits 2-0 (p4)

  // Checksum gate — p1 bits 6,3,1,0 must be zero in valid frames;
  // p4 bit 0 must also be zero.
  {
    uint8_t p1 = digit_bytes[0];
    static constexpr uint8_t CHECKSUM_MASK = 0x4B;  // bits 6,3,1,0
    if ((p1 & CHECKSUM_MASK) != 0x00 || (status & 0x01) != 0x00) {
      ESP_LOGW(TAG, "Frame checksum failed (p1=0x%02X p4=0x%X), dropping", p1, status);
      return;
    }
  }

  // Decode each digit
  char decoded[DIGITS_PER_FRAME + 1];
  for (int i = 0; i < DIGITS_PER_FRAME; i++) {
    decoded[i] = this->decode_7seg_(digit_bytes[i]);
  }
  decoded[DIGITS_PER_FRAME] = '\0';

  std::string display_str(decoded, DIGITS_PER_FRAME);

  // Build raw hex string
  char hex_buf[16];
  snprintf(hex_buf, sizeof(hex_buf), "%02X %02X %02X",
           digit_bytes[0], digit_bytes[1], digit_bytes[2]);
  std::string raw_hex(hex_buf);

  // Build digit values (pipe-separated)
  std::string digit_values;
  for (int i = 0; i < DIGITS_PER_FRAME; i++) {
    if (i > 0)
      digit_values += '|';
    digit_values += decoded[i];
  }

  // Calculate decode confidence (percentage of known characters)
  int known_count = 0;
  for (int i = 0; i < DIGITS_PER_FRAME; i++) {
    if (decoded[i] != '?')
      known_count++;
  }
  float confidence = (static_cast<float>(known_count) / DIGITS_PER_FRAME) * 100.0f;

  // Drop partial frames — transitional display states are not actionable
  if (known_count < DIGITS_PER_FRAME) {
    ESP_LOGD(TAG, "Partial frame dropped (raw: %s, confidence: %.0f%%)", raw_hex.c_str(), confidence);
    return;
  }

  // Stability filter — require STABLE_THRESHOLD consecutive identical decoded frames
  if (display_str == this->candidate_display_string_) {
    if (this->stable_count_ < 255) this->stable_count_++;
  } else {
    this->candidate_display_string_ = display_str;
    this->stable_count_ = 1;
  }
  if (this->stable_count_ < STABLE_THRESHOLD) {
    ESP_LOGD(TAG, "Stability: %d/%d for '%s', holding",
             this->stable_count_, STABLE_THRESHOLD, display_str.c_str());
    return;
  }

  // Only publish on change
  bool changed = false;

  if (display_str != this->last_display_string_) {
    this->last_display_string_ = display_str;
    if (this->display_string_sensor_ != nullptr) {
      this->display_string_sensor_->publish_state(display_str);
    }
    changed = true;
    ESP_LOGD(TAG, "Display: '%s' (raw: %s, frame #%lu)",
             display_str.c_str(), raw_hex.c_str(),
             (unsigned long) this->isr_data_.frame_count);
  }

  if (raw_hex != this->last_raw_hex_) {
    this->last_raw_hex_ = raw_hex;
    if (this->raw_hex_sensor_ != nullptr) {
      this->raw_hex_sensor_->publish_state(raw_hex);
    }
    changed = true;
  }

  if (digit_values != this->last_digit_values_) {
    this->last_digit_values_ = digit_values;
    if (this->digit_values_sensor_ != nullptr) {
      this->digit_values_sensor_->publish_state(digit_values);
    }
    changed = true;
  }

  if (this->decode_confidence_sensor_ != nullptr && confidence != this->last_confidence_) {
    this->last_confidence_ = confidence;
    this->decode_confidence_sensor_->publish_state(confidence);
  }

  // Classify display state (temperature, economy, sleep, etc.)
  this->classify_display_state_(display_str);

  if (changed) {
    this->publish_timestamp_();
  }
}

/// Classify the display string into a state category.
/// Temperature values are published as raw decoded strings (no unit conversion).
/// HA is responsible for interpreting units.
void TublemetryDisplay::classify_display_state_(const std::string &display_str) {
  std::string stripped;
  for (char c : display_str) {
    if (c != ' ')
      stripped += c;
  }

  std::string state;

  // Check if it's a 2-3 digit numeric string (temperature reading)
  bool is_numeric = !stripped.empty() && stripped.length() >= 2 && stripped.length() <= 3;
  if (is_numeric) {
    for (char c : stripped) {
      if (c < '0' || c > '9') {
        is_numeric = false;
        break;
      }
    }
  }

  if (is_numeric) {
    state = "temperature";
    float temp = static_cast<float>(atoi(stripped.c_str()));
    // Feed raw value to button injector for closed-loop verification
    if (this->injector_ != nullptr) {
      this->injector_->feed_display_temperature(temp);
    }
    // Publish to HA temperature sensor
    if (this->temperature_sensor_ != nullptr) {
      this->temperature_sensor_->publish_state(temp);
    }
  } else if (stripped == "OH") {
    state = "OH";
  } else if (stripped == "ICE") {
    state = "ICE";
  } else if (stripped == "Ec") {
    state = "economy";
  } else if (stripped == "SL" || stripped == "5L") {
    state = "sleep";
  } else if (stripped == "St" || stripped == "5t") {
    state = "standby";
  } else if (stripped == "--" || stripped == "---") {
    state = "startup";
  } else if (stripped.empty()) {
    state = "blank";
  } else {
    state = "unknown";
  }

  if (state != this->last_display_state_) {
    this->last_display_state_ = state;
    if (this->display_state_sensor_ != nullptr) {
      this->display_state_sensor_->publish_state(state);
    }
    ESP_LOGD(TAG, "Display state: %s", state.c_str());
  }
}

/// Publish current timestamp to the last_update sensor.
void TublemetryDisplay::publish_timestamp_() {
  if (this->last_update_sensor_ == nullptr)
    return;

  char buf[32];
  snprintf(buf, sizeof(buf), "uptime:%lu", (unsigned long) millis());
  this->last_update_sensor_->publish_state(std::string(buf));
}

}  // namespace tublemetry_display
}  // namespace esphome

#pragma once

#include "esphome/core/component.h"
#include "esphome/core/gpio.h"
#include "esphome/components/text_sensor/text_sensor.h"

#include <string>

namespace esphome {
namespace tublemetry_display {

/// State machine phases for button injection sequence.
enum class InjectorPhase : uint8_t {
  IDLE = 0,       // No sequence in progress
  PROBING,        // One down press to reveal current setpoint from display
  ADJUSTING,      // Pressing up or down to reach target from known setpoint
  VERIFYING,      // Waiting for display stream to confirm setpoint
  COOLDOWN,       // Brief pause after sequence before accepting new requests
  TEST_PRESS,     // Single raw press for hardware testing (bypasses sequence)
};

/// Result of the last completed sequence.
enum class InjectorResult : uint8_t {
  NONE = 0,       // No sequence has run yet
  SUCCESS,        // Display confirmed target temperature
  TIMEOUT,        // Verification timed out waiting for display confirmation
  ABORTED,        // Sequence was aborted (e.g. new request while verifying)
};

/// Non-blocking button injection via photorelay GPIO outputs.
///
/// Strategy:
///   - If the current setpoint is known (cached from last success): calculate
///     the exact delta and press up or down accordingly. No sweep.
///   - If the setpoint is unknown (first boot or reset): press down once to
///     reveal the setpoint on the display (PROBING), then adjust from there.
///
/// All timing is non-blocking — call loop() from the parent component's loop.
class ButtonInjector {
 public:
  // --- Configuration (called from codegen) ---
  void set_temp_up_pin(GPIOPin *pin) { this->temp_up_pin_ = pin; }
  void set_temp_down_pin(GPIOPin *pin) { this->temp_down_pin_ = pin; }

  /// Press duration in milliseconds (how long the relay closes).
  void set_press_duration_ms(uint32_t ms) { this->press_duration_ms_ = ms; }

  /// Delay between presses in milliseconds (relay open between presses).
  void set_inter_press_delay_ms(uint32_t ms) { this->inter_press_delay_ms_ = ms; }

  /// Verification timeout in milliseconds (how long to wait for display confirmation).
  void set_verify_timeout_ms(uint32_t ms) { this->verify_timeout_ms_ = ms; }

  /// Cooldown period after sequence completes before accepting new requests.
  void set_cooldown_ms(uint32_t ms) { this->cooldown_ms_ = ms; }

  // --- Diagnostic sensor setters ---
  void set_injection_state_sensor(text_sensor::TextSensor *s) { this->injection_state_sensor_ = s; }

  // --- Setup (called once from parent setup) ---
  void setup();

  // --- Runtime ---

  /// Request a temperature change. Returns true if accepted, false if rejected
  /// (out of range, sequence in progress, no pins configured).
  bool request_temperature(float target);

  /// Fire a single raw button press for hardware validation. Only works when IDLE.
  void press_once(bool temp_up);

  /// Drive the state machine. Call every loop() iteration.
  void loop();

  /// Feed the current display temperature from the decode pipeline.
  /// Used during PROBING and VERIFYING to read the current setpoint.
  void feed_display_temperature(float temp);

  /// Abort any in-progress sequence and return to IDLE.
  void abort();

  // --- Status queries ---
  InjectorPhase phase() const { return this->phase_; }
  InjectorResult last_result() const { return this->last_result_; }
  float target_temperature() const { return this->target_temp_; }
  bool is_busy() const { return this->phase_ != InjectorPhase::IDLE; }
  bool is_configured() const { return this->temp_up_pin_ != nullptr && this->temp_down_pin_ != nullptr; }

  // --- Constants ---
  static constexpr float TEMP_FLOOR = 80.0f;
  static constexpr float TEMP_CEILING = 104.0f;

  // --- String helpers ---
  static const char *phase_to_string(InjectorPhase phase);
  static const char *result_to_string(InjectorResult result);

 protected:
  // GPIO pins (nullptr = not configured = read-only mode)
  GPIOPin *temp_up_pin_{nullptr};
  GPIOPin *temp_down_pin_{nullptr};

  // Timing configuration (defaults)
  uint32_t press_duration_ms_{200};
  uint32_t inter_press_delay_ms_{300};
  uint32_t verify_timeout_ms_{10000};
  uint32_t cooldown_ms_{1000};

  // State machine
  InjectorPhase phase_{InjectorPhase::IDLE};
  InjectorResult last_result_{InjectorResult::NONE};

  // Sequence state
  float target_temp_{0.0f};
  float known_setpoint_{NAN};      // cached setpoint after successful sequences; NAN = unknown
  uint8_t presses_remaining_{0};
  uint8_t presses_total_{0};
  bool pin_active_{false};         // true = relay is currently closed (button pressed)
  bool adjusting_up_{true};        // direction for ADJUSTING phase
  bool test_press_up_{false};      // direction for TEST_PRESS phase
  uint32_t phase_start_ms_{0};     // millis() when current phase began
  uint32_t last_action_ms_{0};     // millis() of last pin state change
  float last_display_temp_{NAN};   // last temperature fed from display stream
  float probed_setpoint_{NAN};     // setpoint captured during PROBING phase

  // Diagnostics
  uint32_t sequence_count_{0};
  uint32_t success_count_{0};
  std::string last_error_;

  // Diagnostic sensors
  text_sensor::TextSensor *injection_state_sensor_{nullptr};

  // Internal methods
  void transition_to_(InjectorPhase new_phase);
  void start_adjusting_(float from_setpoint);
  void loop_probing_();
  void loop_adjusting_();
  void loop_verifying_();
  void loop_cooldown_();
  void loop_test_press_();
  void press_pin_(GPIOPin *pin);
  void release_pin_(GPIOPin *pin);
  void release_all_pins_();
  void publish_state_();
  void finish_sequence_(InjectorResult result, const std::string &error = "");
};

}  // namespace tublemetry_display
}  // namespace esphome

#include "button_injector.h"
#include "esphome/core/log.h"
#include "esphome/core/hal.h"

#include <cmath>

namespace esphome {
namespace tublemetry_display {

static const char *const TAG = "button_injector";

// --- String helpers ---

const char *ButtonInjector::phase_to_string(InjectorPhase phase) {
  switch (phase) {
    case InjectorPhase::IDLE:       return "idle";
    case InjectorPhase::PROBING:    return "probing";
    case InjectorPhase::ADJUSTING:  return "adjusting";
    case InjectorPhase::VERIFYING:  return "verifying";
    case InjectorPhase::COOLDOWN:   return "cooldown";
    case InjectorPhase::TEST_PRESS: return "test_press";
    default:                        return "unknown";
  }
}

const char *ButtonInjector::result_to_string(InjectorResult result) {
  switch (result) {
    case InjectorResult::NONE:    return "none";
    case InjectorResult::SUCCESS: return "success";
    case InjectorResult::TIMEOUT: return "timeout";
    case InjectorResult::ABORTED: return "aborted";
    default:                      return "unknown";
  }
}

// --- Setup ---

void ButtonInjector::setup() {
  if (this->temp_up_pin_ == nullptr || this->temp_down_pin_ == nullptr) {
    ESP_LOGW(TAG, "Button injection pins not configured — read-only mode");
    return;
  }

  this->temp_up_pin_->setup();
  this->temp_down_pin_->setup();

  // Ensure relays start open (pins LOW = relay off for AQY212EH)
  this->temp_up_pin_->digital_write(false);
  this->temp_down_pin_->digital_write(false);

  ESP_LOGI(TAG, "Button injection ready — pins configured");
  ESP_LOGI(TAG, "Timing: press=%dms, gap=%dms, verify_timeout=%dms, cooldown=%dms",
           (int) this->press_duration_ms_, (int) this->inter_press_delay_ms_,
           (int) this->verify_timeout_ms_, (int) this->cooldown_ms_);

  this->publish_state_();
}

// --- Request temperature ---

bool ButtonInjector::request_temperature(float target) {
  if (!this->is_configured()) {
    ESP_LOGW(TAG, "Cannot set temperature — injection pins not configured");
    return false;
  }

  if (this->is_busy()) {
    ESP_LOGW(TAG, "Cannot set temperature — sequence in progress (phase: %s)",
             phase_to_string(this->phase_));
    return false;
  }

  // Safety clamp
  if (target < TEMP_FLOOR || target > TEMP_CEILING) {
    ESP_LOGW(TAG, "Target %.0fF outside safe range (%.0f-%.0fF) — rejected",
             target, TEMP_FLOOR, TEMP_CEILING);
    return false;
  }

  target = roundf(target);
  this->target_temp_ = target;
  this->sequence_count_++;

  if (!std::isnan(this->known_setpoint_)) {
    // Setpoint is known — go directly to adjusting (no probe needed)
    ESP_LOGI(TAG, "Starting sequence #%lu: %.0fF -> %.0fF (known setpoint)",
             (unsigned long) this->sequence_count_,
             this->known_setpoint_, target);
    this->start_adjusting_(this->known_setpoint_);
  } else {
    // Setpoint unknown — probe with one down press to discover it
    ESP_LOGI(TAG, "Starting sequence #%lu: target %.0fF — probing setpoint",
             (unsigned long) this->sequence_count_, target);
    this->probed_setpoint_ = NAN;
    this->transition_to_(InjectorPhase::PROBING);
  }

  return true;
}

// --- Single test press ---

void ButtonInjector::press_once(bool temp_up) {
  if (!this->is_configured()) {
    ESP_LOGW(TAG, "Cannot test press — pins not configured");
    return;
  }
  if (this->is_busy()) {
    ESP_LOGW(TAG, "Cannot test press — sequence in progress (phase: %s)",
             phase_to_string(this->phase_));
    return;
  }
  this->test_press_up_ = temp_up;
  this->known_setpoint_ = NAN;  // test press changes real setpoint — probe on next sequence
  ESP_LOGI(TAG, "Test press: %s (setpoint cache cleared)", temp_up ? "temp_up" : "temp_down");
  this->transition_to_(InjectorPhase::TEST_PRESS);
}

// --- start_adjusting_ helper ---

void ButtonInjector::start_adjusting_(float from_setpoint) {
  int delta = static_cast<int>(roundf(this->target_temp_)) - static_cast<int>(roundf(from_setpoint));

  if (delta == 0) {
    // Already at target — skip straight to verify
    ESP_LOGI(TAG, "Already at %.0fF — skipping adjust, verifying", this->target_temp_);
    this->transition_to_(InjectorPhase::VERIFYING);
    return;
  }

  this->adjusting_up_ = (delta > 0);
  this->presses_remaining_ = static_cast<uint8_t>(std::abs(delta));
  this->presses_total_ = this->presses_remaining_;

  ESP_LOGI(TAG, "Adjusting: %d %s-presses from %.0fF to %.0fF",
           (int) this->presses_total_,
           this->adjusting_up_ ? "up" : "down",
           from_setpoint, this->target_temp_);
  this->transition_to_(InjectorPhase::ADJUSTING);
}

// --- Main loop ---

void ButtonInjector::loop() {
  switch (this->phase_) {
    case InjectorPhase::IDLE:
      return;
    case InjectorPhase::PROBING:
      this->loop_probing_();
      break;
    case InjectorPhase::ADJUSTING:
      this->loop_adjusting_();
      break;
    case InjectorPhase::VERIFYING:
      this->loop_verifying_();
      break;
    case InjectorPhase::COOLDOWN:
      this->loop_cooldown_();
      break;
    case InjectorPhase::TEST_PRESS:
      this->loop_test_press_();
      break;
  }
}

// --- Phase loops ---

void ButtonInjector::loop_probing_() {
  uint32_t now = millis();
  uint32_t elapsed = now - this->last_action_ms_;

  if (this->pin_active_) {
    // Press is active — wait for press duration then release
    if (elapsed >= this->press_duration_ms_) {
      this->release_pin_(this->temp_down_pin_);
      this->pin_active_ = false;
      this->last_action_ms_ = now;
    }
  } else if (std::isnan(this->probed_setpoint_)) {
    if (elapsed < this->inter_press_delay_ms_) {
      // Still waiting after release for display to update
      return;
    }

    // Time to fire the probe press or read the result
    if (this->phase_start_ms_ == this->last_action_ms_) {
      // Haven't pressed yet — fire the probe down press
      this->press_pin_(this->temp_down_pin_);
      this->pin_active_ = true;
      this->last_action_ms_ = now;
    } else {
      // Press has been released and we've waited — read the display
      if (!std::isnan(this->last_display_temp_)) {
        // Display shows the new setpoint (old - 1) after our down press
        this->probed_setpoint_ = this->last_display_temp_;
        ESP_LOGI(TAG, "Probed setpoint: %.0fF (display after down press)", this->probed_setpoint_);
        this->start_adjusting_(this->probed_setpoint_);
      } else {
        // No display reading yet — keep waiting (verify timeout will catch runaway)
        uint32_t total_elapsed = now - this->phase_start_ms_;
        if (total_elapsed >= this->verify_timeout_ms_) {
          this->finish_sequence_(InjectorResult::TIMEOUT, "probe: no display reading");
        }
      }
    }
  }
}

void ButtonInjector::loop_adjusting_() {
  uint32_t now = millis();
  uint32_t elapsed = now - this->last_action_ms_;
  GPIOPin *pin = this->adjusting_up_ ? this->temp_up_pin_ : this->temp_down_pin_;

  if (this->pin_active_) {
    if (elapsed >= this->press_duration_ms_) {
      this->release_pin_(pin);
      this->pin_active_ = false;
      this->last_action_ms_ = now;
      this->presses_remaining_--;

      uint8_t completed = this->presses_total_ - this->presses_remaining_;
      ESP_LOGD(TAG, "Adjust press %d/%d complete (%s)",
               (int) completed, (int) this->presses_total_,
               this->adjusting_up_ ? "up" : "down");

      if (this->presses_remaining_ == 0) {
        ESP_LOGI(TAG, "Adjust complete — verifying display shows %.0fF", this->target_temp_);
        this->transition_to_(InjectorPhase::VERIFYING);
      }
    }
  } else {
    if (elapsed >= this->inter_press_delay_ms_) {
      this->press_pin_(pin);
      this->pin_active_ = true;
      this->last_action_ms_ = now;
    }
  }
}

void ButtonInjector::loop_verifying_() {
  uint32_t now = millis();
  uint32_t elapsed = now - this->phase_start_ms_;

  if (!std::isnan(this->last_display_temp_) &&
      this->last_display_temp_ == this->target_temp_) {
    ESP_LOGI(TAG, "Verified: display shows %.0fF — sequence successful", this->target_temp_);
    this->finish_sequence_(InjectorResult::SUCCESS);
    return;
  }

  if (elapsed >= this->verify_timeout_ms_) {
    ESP_LOGW(TAG, "Verification timeout after %dms — display shows %.0fF, expected %.0fF",
             (int) elapsed,
             std::isnan(this->last_display_temp_) ? -1.0f : this->last_display_temp_,
             this->target_temp_);
    this->finish_sequence_(InjectorResult::TIMEOUT, "verification timeout");
  }
}

void ButtonInjector::loop_cooldown_() {
  uint32_t now = millis();
  uint32_t elapsed = now - this->phase_start_ms_;

  if (elapsed >= this->cooldown_ms_) {
    ESP_LOGD(TAG, "Cooldown complete — ready for next sequence");
    this->transition_to_(InjectorPhase::IDLE);
  }
}

void ButtonInjector::loop_test_press_() {
  uint32_t now = millis();
  uint32_t elapsed = now - this->last_action_ms_;
  GPIOPin *pin = this->test_press_up_ ? this->temp_up_pin_ : this->temp_down_pin_;

  if (this->pin_active_) {
    if (elapsed >= this->press_duration_ms_) {
      this->release_pin_(pin);
      this->pin_active_ = false;
      ESP_LOGI(TAG, "Test press complete (%s)", this->test_press_up_ ? "up" : "down");
      this->transition_to_(InjectorPhase::COOLDOWN);
    }
  } else {
    if (elapsed >= this->inter_press_delay_ms_) {
      this->press_pin_(pin);
      this->pin_active_ = true;
      this->last_action_ms_ = now;
    }
  }
}

// --- Feed display temperature ---

void ButtonInjector::feed_display_temperature(float temp) {
  this->last_display_temp_ = temp;
}

// --- Abort ---

void ButtonInjector::abort() {
  if (this->phase_ == InjectorPhase::IDLE) {
    return;
  }

  ESP_LOGW(TAG, "Aborting sequence in phase: %s", phase_to_string(this->phase_));
  this->release_all_pins_();
  this->finish_sequence_(InjectorResult::ABORTED, "manually aborted");
}

// --- Internal helpers ---

void ButtonInjector::transition_to_(InjectorPhase new_phase) {
  ESP_LOGD(TAG, "Phase: %s -> %s", phase_to_string(this->phase_), phase_to_string(new_phase));
  this->phase_ = new_phase;
  this->phase_start_ms_ = millis();
  this->last_action_ms_ = millis();
  this->pin_active_ = false;
  this->publish_state_();
}

void ButtonInjector::press_pin_(GPIOPin *pin) {
  if (pin != nullptr) {
    pin->digital_write(true);
  }
}

void ButtonInjector::release_pin_(GPIOPin *pin) {
  if (pin != nullptr) {
    pin->digital_write(false);
  }
}

void ButtonInjector::release_all_pins_() {
  this->release_pin_(this->temp_up_pin_);
  this->release_pin_(this->temp_down_pin_);
  this->pin_active_ = false;
}

void ButtonInjector::publish_state_() {
  if (this->injection_state_sensor_ != nullptr) {
    std::string state = phase_to_string(this->phase_);
    if (this->phase_ != InjectorPhase::IDLE && this->target_temp_ > 0) {
      char buf[32];
      snprintf(buf, sizeof(buf), "%s:%.0f", state.c_str(), this->target_temp_);
      state = std::string(buf);
    }
    this->injection_state_sensor_->publish_state(state);
  }
}

void ButtonInjector::finish_sequence_(InjectorResult result, const std::string &error) {
  this->release_all_pins_();
  this->last_result_ = result;
  this->last_error_ = error;

  if (result == InjectorResult::SUCCESS) {
    this->success_count_++;
    // Cache the confirmed setpoint for direct-delta on next call
    this->known_setpoint_ = this->target_temp_;
  } else {
    // Timeout or abort: setpoint location is uncertain — force probe on next sequence
    this->known_setpoint_ = NAN;
  }

  ESP_LOGI(TAG, "Sequence #%lu finished: %s (total: %lu success, %lu total)",
           (unsigned long) this->sequence_count_,
           result_to_string(result),
           (unsigned long) this->success_count_,
           (unsigned long) this->sequence_count_);

  if (!error.empty()) {
    ESP_LOGW(TAG, "Last error: %s", error.c_str());
  }

  this->transition_to_(InjectorPhase::COOLDOWN);
}

